#include&lt;iostream&gt;
#include&lt;cmath&gt;
using namespace std;
class Point&#123;
private:
    float x, y;
public:
    Point();//不带参的构造函数
    Point(float xx, float yy);//带参的构造函数
    void set();
    void show();
    Point calc(Point p);
    float getX();
    float getY();
    //这两个函数是得到point类私有数据的关键函数，外部不可以直接访问类的私有数据，需要通过些特殊手段
&#125;;

Point::Point()
&#123;
    x = 0;
    y = 0;
&#125;

Point::Point(float xx,float yy)
&#123;
    x = xx;
    y = yy;
&#125;

void Point::set()
&#123;
    cout &lt;&lt; &quot;enter the x and y: &quot;;
    cin &gt;&gt; x &gt;&gt; y;
&#125;

void Point::show()
&#123;
    cout &lt;&lt; &quot;x = &quot; &lt;&lt; x &lt;&lt; endl;
    cout &lt;&lt; &quot;y = &quot; &lt;&lt; y &lt;&lt; endl;
&#125;

Point Point::calc(Point p)
&#123;
    Point temp;
    temp.x = (x - p.x) * (x - p.x);
    temp.y = (y - p.y) * (y - p.y);
//类内部函数可以直接使用p.x和p.y来调用数据
    return temp;
&#125;

float Point::getX()
&#123;
    return x;
&#125;

float Point::getY()
&#123;
    return y;
&#125;

float calc_dis(Point p)
&#123;
    float x, y, dis;
    x = p.getX();
    y = p.getY();
//非类内部函数直接用p.x+p.y会报错    
    dis = sqrt(x + y);
    return dis;
&#125;

int main()
&#123;
    Point p2, p3;
    float dis;
    // p1.set();
    Point p1(4, 5);
    Point p4;
    p2.set();
    //p1.show();
    // p2.show();
    p3 = p2.calc(p1);
    dis = calc_dis(p3);
    cout &lt;&lt; &quot;distance = &quot; &lt;&lt; dis &lt;&lt; endl;
    p4.show();
&#125;

