#include&lt;iostream&gt;
#include&lt;string&gt;
using namespace std;

typedef struct student &#123;
    string name, ID, publisher, author;
    student* next;
&#125; student, * stu;

class list &#123;
public:
    ~list();//析构函数
    list(string, string, string, string);//构造函数
    void search(string name);
    void insert(string, string, string, string);
    void del(string);
    void print();
    void edit(string);
    struct student* head;
&#125;;

list::~list()
&#123;
    cout &lt;&lt; &quot;release successfully&quot; &lt;&lt; endl;
    system(&quot;pause&quot;);
&#125;
//析构函数不要出现在主函数里，不然会报错

list::list(string a, string b, string c, string d)
&#123;
    head = new student;
    head-&gt;next = NULL;
    student* s = NULL;
    s = new student;
    s-&gt;name = a;
    s-&gt;ID = b;
    s-&gt;author = c;
    s-&gt;publisher = d;
    s-&gt;next = head-&gt;next;
    head-&gt;next = s;
&#125;
//初始化链表

void list::search(string name)
&#123;
    student* p = head-&gt;next;
    while (p != NULL) &#123;
        if (p-&gt;name == name) &#123;
            //return p;
            cout &lt;&lt; &quot;name: &quot; &lt;&lt; p-&gt;name &lt;&lt; endl;
            cout &lt;&lt; &quot;ID: &quot; &lt;&lt; p-&gt;ID &lt;&lt; endl;
            cout &lt;&lt; &quot;author: &quot; &lt;&lt; p-&gt;author &lt;&lt; endl;
            cout &lt;&lt; &quot;publisher: &quot; &lt;&lt; p-&gt;publisher &lt;&lt; endl;
            break;
        &#125;
        p = p-&gt;next;
    &#125;
    system(&quot;pause&quot;);
    //return NULL;
&#125;
//查找链表中的成员

void list::insert(string a, string b, string c, string d)
&#123;
    student* p = head, * s = NULL;
    s = new student;
    s-&gt;name = a;
    s-&gt;ID = b;
    s-&gt;author = c;
    s-&gt;publisher = d;
    s-&gt;next = p-&gt;next;
    head-&gt;next = s;
&#125;
//往链表添加新成员

void list::del(string name)
&#123;
    student* p = head-&gt;next, * s = head, * q = NULL;
    q = new student;
    while (p != NULL &amp;&amp; p-&gt;name != name) &#123;
        p = p-&gt;next;
        s = s-&gt;next;
    &#125;
    if (p-&gt;name == name) &#123;
        s-&gt;next = p-&gt;next;
        q = p;
        delete q;
        cout &lt;&lt; &quot;delete successfully&quot; &lt;&lt; endl;
    &#125;
&#125;
//删除链表的结点

void list::print()
&#123;
    student* p = head-&gt;next;
    cout &lt;&lt; &quot;name\t&quot; &lt;&lt; &quot;ID\t&quot; &lt;&lt; &quot;author\t&quot; &lt;&lt; &quot;publisher&quot; &lt;&lt; endl;
    while (p != NULL) &#123;
        cout &lt;&lt; p-&gt;name &lt;&lt; &#39;\t&#39; &lt;&lt; p-&gt;ID &lt;&lt; &#39;\t&#39; &lt;&lt; p-&gt;author &lt;&lt; &#39;\t&#39; &lt;&lt; p-&gt;publisher &lt;&lt; endl;
        p = p-&gt;next;
    &#125;
    cout &lt;&lt; endl;
&#125;
//打印链表

void list::edit(string name)
&#123;
    student* p = head-&gt;next;
    while (p != NULL) &#123;
        if (p-&gt;name == name) &#123;
            break;
        &#125;
        p = p-&gt;next;
    &#125;
    while (1) &#123;
        cout &lt;&lt; &quot;what data do you wanna edit(enter &#39;none&#39; to exit): &quot;;
        string temp;
        cin &gt;&gt; temp;
        cout &lt;&lt; &quot;enter the new data: &quot;;
        if (temp == name) &#123;
            cin &gt;&gt; p-&gt;name;
        &#125;
        else if (temp == &quot;ID&quot;) &#123;
            cin &gt;&gt; p-&gt;ID;
        &#125;
        else if (temp == &quot;author&quot;) &#123;
            cin &gt;&gt; p-&gt;author;
        &#125;
        else if (temp == &quot;publisher&quot;) &#123;
            cin &gt;&gt; p-&gt;publisher;
        &#125;
        else if (temp == &quot;none&quot;) &#123;
            break;
        &#125;
        else &#123;
            cout &lt;&lt; &quot;error, please check what you enter&quot; &lt;&lt; endl;
        &#125;

    &#125;
&#125;
//编辑链表成员的数据

int main()
&#123;
