//二分查找判断某个元素是否在序列里
long search(int a[],int low,int high,int k)&#123;
    if(low &lt;= high)&#123;
        int mid = low + (high - low) / 2;
        if(k == a[mid])&#123;
            return 1;//找到了返回1
        &#125;else if(a[mid] &gt; k)&#123;
//比中值小在左边找            
            return search(a, low, mid - 1, k);
        &#125;else&#123;
//比中值大在右边找            
            return search(a, mid + 1, high, k);
        &#125;
    &#125;
    return 0;
//如果都找不到默认返回0    
&#125;

