//1.从左逼近(直接丢函数包)
long fun(long a[],long low,long high,long key)
&#123;
    int mid = low + (low + high) / 2;
    if(low &lt;= high)&#123;
        if(a[mid] &lt; key)&#123;
//在右边查找            
            return fun(a, mid + 1, high, key);
        &#125;
        if(a[mid] &gt; key)&#123;
//在左边查找            
            return fun(a, low, mid - 1, key);
        &#125;
        else&#123;
/*如果找到目标元素，判断有无重复，有的话取最大下标*/
            while(mid&gt;=0)&#123;
                if(a[mid]!=key)&#123;
                    break;
                &#125;
                mid++;
            &#125;
        &#125;
    &#125;
    return mid;
&#125;

