/*链表合集*/
#include&lt;iostream&gt;
#include&lt;cstdlib&gt;
using namespace std;
typedef struct node&#123;
    int a;
    struct node *next;
&#125; Node;
//排序
void Sort(Node*head)&#123;
    node *p, *s, *pt;
    p = head;
    s = p-&gt;next;
    while (p-&gt;next != NULL)&#123;
        while(s-&gt;next != NULL)&#123;
            if(p-&gt;next &gt; s-&gt;next)&#123;
                pt-&gt;next = p-&gt;next;
                p-&gt;next = s-&gt;next;
                s-&gt;next = pt-&gt;next;
            &#125;
            s = s-&gt;next;
        &#125;
        p = p-&gt;next;
        pt = s;
    &#125;
&#125;

Node *add(Node*head,int num)&#123;//在表尾插入元素
    Node *p = NULL, *pr = head;
    p = (Node *)malloc(sizeof(Node));
    if(p == NULL)&#123;
        cout &lt;&lt; &quot;no enough memory to allocate&quot;;
    &#125;
    if(head == NULL)&#123;
        head = p;
    &#125;else&#123;
        while(pr-&gt;next != NULL)&#123;
            pr = pr-&gt;next;
        &#125;
        pr-&gt;next = p;
    &#125;
    p-&gt;a = num;
    p-&gt;next = NULL;
    return head;
&#125;
//打印链表
void show(Node*head)&#123;
    Node *p = head;
    while(p != NULL)&#123;
        cout &lt;&lt; p-&gt;a &lt;&lt; &quot; &quot;;
        p = p-&gt;next;
    &#125;
&#125;

void del(Node*head)&#123;//释放申请的内存空间
    Node *p = head, *pr = NULL;
    while(p != NULL)&#123;
        pr = p;
        p = p-&gt;next;
        free(pr);
    &#125;
&#125;
//删除链表里某一个节点
Node* Delete(Node*head,int num)&#123;
    Node *p = head, *pr = head;
    //pr是目标元素前一个节点
    if(head == NULL)&#123;
        cout &lt;&lt; &quot;empty table&quot;;
        return head;//空表退出
    &#125;
    while(num != p-&gt;a &amp;&amp; p-&gt;next != NULL)&#123;
        //未找到且不是空表
        pr = p;
        p = p-&gt;next;//p直接指向当前节点的下一节点
    &#125;
    if(num == p-&gt;a)&#123;//找到了待删除节点
        if(p == head)&#123;
            head = p-&gt;next;//直接让头指针指向待删除结点p的下一节点
        &#125;else&#123;
            pr-&gt;next = p-&gt;next;
            //前一节点的指针域指向待删除结点的下一节点
        &#125;
        free(p);
    &#125;else&#123;//到表尾且没找到
        cout &lt;&lt; &quot;not found&quot;;
    &#125;
    return head;
&#125;
//在链表里插入元素
Node* insert(Node*head,int num)&#123;
    Node *pr = head, *p = head, *temp = NULL;
    p = (Node *)malloc(sizeof(Node));
    if(p == NULL)&#123;
        cout &lt;&lt; &quot;no enough memory&quot;;
        exit(0);
    &#125;
    p-&gt;next = NULL;//待插入节点指针域为空指针
    p-&gt;a = num;//待插入节点的数值域为num
    if(head == NULL)&#123;
        head = p;//若原链表为空表，待插入节点为头节点
    &#125;else&#123;//若为非空
    //若未找到待插入节点的位置且未找到表尾则继续找
        while(pr-&gt;a &lt; num &amp;&amp; pr-&gt;next != NULL)&#123;
            temp = pr;//temp保存当前节点的下一节点
            pr = pr-&gt;next;//pr指向当前节点的下一节点
        &#125;
        if(pr-&gt;a &gt;= num)&#123;
            if(pr == head)&#123;//若在头节点前插入新节点
                p-&gt;next = head;
            //将新节点的指针域指向原链表的头节点
                head = p;//让head指向新节点
            &#125;else&#123;//在链表中部插入新节点
            //进行排序
                pr = temp;
                p-&gt;next = pr-&gt;next;
                pr-&gt;next = p;
            &#125;
        &#125;else&#123;//若在表尾插入新节点
            pr-&gt;next = p;//让末节点的指针域指向新节点
        &#125;
    &#125;
    return head;//返回插入新节点猴的链表头指针head的值
&#125;

